# Xem DHCP pool configuration (isc-dhcp-server)
cat /etc/dhcp/dhcpd.conf

# Xem lease hiện tại của server
cat /var/lib/dhcp/dhcpd.leases

# Ví dụ cấu hình pool:
# subnet 192.168.1.0 netmask 255.255.255.0 {
#   range 192.168.1.50 192.168.1.200;
#   option routers 192.168.1.1;
#   option domain-name-servers 8.8.8.8;
#   default-lease-time 86400;
# }

# === Server setup ===
# 1. dhcpd.conf bật ping-check
sudo tee /etc/dhcp/dhcpd.conf >/dev/null <<'EOF'
default-lease-time 120;
max-lease-time 300;
authoritative;
ping-check true;
ping-timeout 1;
subnet 192.168.81.0 netmask 255.255.255.0 {
  range 192.168.81.200 192.168.81.201;
  option routers 192.168.81.2;
  option domain-name-servers 8.8.8.8, 1.1.1.1;
}
EOF

# 2. systemd drop-in để dhcpd chạy as ROOT (CAP_NET_RAW)
sudo mkdir -p /etc/systemd/system/isc-dhcp-server.service.d
sudo tee /etc/systemd/system/isc-dhcp-server.service.d/override.conf >/dev/null <<'EOF'
[Service]
ExecStart=
ExecStart=/usr/sbin/dhcpd -f -4 -pf /run/dhcp-server/dhcpd.pid \
  -cf /etc/dhcp/dhcpd.conf ens33
EOF
sudo chown root:root /var/lib/dhcp /var/lib/dhcp/dhcpd.leases
sudo systemctl daemon-reload
sudo systemctl restart isc-dhcp-server

# 3. Verify CapEff (PHẢI = 000001ffffffffff)
grep CapEff /proc/$(pidof dhcpd | awk '{print $1}')/status

